import AdminSidebar from "../../components/AdminSidebar";
import "./admin.css";

export default function Dashboard() {
  return (
    <div className="admin-layout">
      <AdminSidebar />

      <div className="admin-main">
        <h2>Admin Dashboard</h2>

        <div className="dash-cards">
          <div className="dash-card">Patients</div>
          <div className="dash-card">Visits</div>
          <div className="dash-card">EMR</div>
          <div className="dash-card">Billing</div>
        </div>
      </div>
    </div>
  );
}
